import React, { useState } from 'react';
import { 
  ChevronDown, 
  ChevronLeft, 
  Trash2, 
  Star, 
  Plus,
  Check
} from 'lucide-react';
import Sidebar from '../shared/Sidebar';
import FirstColumn from '../shared/FirstColumn';

const TodosPage = ({ onNavigate }) => {
  const [selectedPeriod, setSelectedPeriod] = useState('Today');
  const [showPeriodDropdown, setShowPeriodDropdown] = useState(false);
  const [selectedTodo, setSelectedTodo] = useState(null);
  const [newTodoText, setNewTodoText] = useState('');
  const [newStepText, setNewStepText] = useState('');
  const [showNewStep, setShowNewStep] = useState(false);
  const [notes, setNotes] = useState('');

  // Mock data for todos
  const [todos, setTodos] = useState([
    {
      id: 1,
      description: 'Review project proposal',
      completed: false,
      time: '08:30am - 10:00am',
      priority: 'High',
      starred: false,
      steps: [
        { id: 1, description: 'Read document', completed: true },
        { id: 2, description: 'Prepare feedback', completed: false }
      ],
      createdAt: '5m ago'
    },
    {
      id: 2,
      description: 'Team meeting preparation',
      completed: true,
      time: '10:30am - 11:00am',
      priority: 'Medium',
      starred: true,
      steps: [],
      createdAt: '2h ago'
    },
    {
      id: 3,
      description: 'Update documentation',
      completed: false,
      time: '02:00pm - 04:00pm',
      priority: 'Low',
      starred: false,
      steps: [
        { id: 1, description: 'Review current docs', completed: false },
        { id: 2, description: 'Add new sections', completed: false },
        { id: 3, description: 'Proofread', completed: false }
      ],
      createdAt: '1d ago'
    }
  ]);

  // Mock data for groups
  const groups = [
    { id: 1, name: 'Work Projects', color: 'bg-blue-500' },
    { id: 2, name: 'Personal', color: 'bg-green-500' },
    { id: 3, name: 'Learning', color: 'bg-purple-500' },
    { id: 4, name: 'Health', color: 'bg-red-500' }
  ];

  const periodOptions = ['Today', 'Yesterday', 'Last week', 'Last month'];

  const priorityColors = {
    'High': 'text-red-500 border-red-500',
    'Medium': 'text-yellow-500 border-yellow-500',
    'Low': 'text-green-500 border-green-500'
  };

  const getCurrentDate = () => {
    const today = new Date();
    const options = { 
      weekday: 'short', 
      day: 'numeric', 
      month: 'long', 
      year: 'numeric' 
    };
    return today.toLocaleDateString('en-US', options);
  };

  const toggleTodoComplete = (todoId) => {
    setTodos(todos.map(todo => 
      todo.id === todoId ? { ...todo, completed: !todo.completed } : todo
    ));
  };

  const toggleStarred = (todoId) => {
    setTodos(todos.map(todo => 
      todo.id === todoId ? { ...todo, starred: !todo.starred } : todo
    ));
  };

  const deleteTodo = (todoId) => {
    setTodos(todos.filter(todo => todo.id !== todoId));
    if (selectedTodo && selectedTodo.id === todoId) {
      setSelectedTodo(null);
    }
  };

  const addNewTodo = () => {
    if (newTodoText.trim()) {
      const newTodo = {
        id: Date.now(),
        description: newTodoText,
        completed: false,
        time: '09:00am - 10:00am',
        priority: 'Medium',
        starred: false,
        steps: [],
        createdAt: 'now'
      };
      setTodos([...todos, newTodo]);
      setNewTodoText('');
    }
  };

  const addStep = () => {
    if (newStepText.trim() && selectedTodo) {
      const newStep = {
        id: Date.now(),
        description: newStepText,
        completed: false
      };

      const updatedTodos = todos.map(todo => 
        todo.id === selectedTodo.id 
          ? { ...todo, steps: [...todo.steps, newStep] }
          : todo
      );

      setTodos(updatedTodos);
      setSelectedTodo({ ...selectedTodo, steps: [...selectedTodo.steps, newStep] });
      setNewStepText('');
    }
  };

  const toggleStepComplete = (stepId) => {
    const updatedTodos = todos.map(todo => 
      todo.id === selectedTodo.id 
        ? { 
            ...todo, 
            steps: todo.steps.map(step => 
              step.id === stepId ? { ...step, completed: !step.completed } : step
            )
          }
        : todo
    );

    setTodos(updatedTodos);
    const updatedTodo = updatedTodos.find(todo => todo.id === selectedTodo.id);
    setSelectedTodo(updatedTodo);
  };

  const deleteStep = (stepId) => {
    const updatedTodos = todos.map(todo => 
      todo.id === selectedTodo.id 
        ? { ...todo, steps: todo.steps.filter(step => step.id !== stepId) }
        : todo
    );

    setTodos(updatedTodos);
    const updatedTodo = updatedTodos.find(todo => todo.id === selectedTodo.id);
    setSelectedTodo(updatedTodo);
  };

  // Sort todos: starred first, then by completion status
  const sortedTodos = [...todos].sort((a, b) => {
    if (a.starred && !b.starred) return -1;
    if (!a.starred && b.starred) return 1;
    if (a.completed && !b.completed) return 1;
    if (!a.completed && b.completed) return -1;
    return 0;
  });

  return (
    <div className="min-h-screen bg-neutral-800">
      <div className="flex gap-4 h-screen">
        {/* First column: 60px */}
        <div className="h-full" style={{ width: '60px' }}>
          <FirstColumn />
        </div>

        {/* Second column: 300px - Sidebar */}
        <div className="h-full" style={{ width: '300px' }}>
          <Sidebar currentPage="todos" onNavigate={onNavigate} />
        </div>

        {/* Third column: flex-1 - Main content */}
        <div className="flex-1 flex gap-6 py-4">
          {/* Main Content */}
          <div className="flex-1 flex flex-col">
            {/* Header */}
            <div className="flex items-center justify-between mb-6">
              <div>
                <h1 className="text-white text-2xl font-bold mb-1">To-dos</h1>
                <p className="text-neutral-400 text-sm">{getCurrentDate()}</p>
              </div>

              {/* Period Dropdown */}
              <div className="relative">
                <button
                  onClick={() => setShowPeriodDropdown(!showPeriodDropdown)}
                  className="flex items-center gap-2 px-4 py-2 bg-neutral-700 border border-neutral-600 rounded-lg text-white hover:bg-neutral-600 transition-colors"
                >
                  <span>{selectedPeriod}</span>
                  <ChevronDown className="w-4 h-4" />
                </button>

                {showPeriodDropdown && (
                  <div className="absolute top-full right-0 mt-1 bg-neutral-800 border border-neutral-700 rounded-lg shadow-lg z-10 min-w-[150px]">
                    {periodOptions.map(option => (
                      <button
                        key={option}
                        onClick={() => {
                          setSelectedPeriod(option);
                          setShowPeriodDropdown(false);
                        }}
                        className="w-full text-left px-3 py-2 text-white hover:bg-neutral-700 transition-colors first:rounded-t-lg last:rounded-b-lg"
                      >
                        {option}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </div>

            {/* Todos List */}
            <div className="flex-1 overflow-y-auto space-y-3 mb-20">
              {sortedTodos.map(todo => (
                <div
                  key={todo.id}
                  className="bg-neutral-700 border border-neutral-600 rounded-lg p-4 hover:bg-neutral-600 transition-colors cursor-pointer"
                  onClick={() => setSelectedTodo(todo)}
                >
                  <div className="flex items-start gap-3">
                    {/* Checkbox */}
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        toggleTodoComplete(todo.id);
                      }}
                      className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-colors ${
                        todo.completed 
                          ? 'bg-green-500 border-green-500' 
                          : 'border-neutral-400 hover:border-white'
                      }`}
                    >
                      {todo.completed && <Check className="w-3 h-3 text-white" />}
                    </button>

                    {/* Content */}
                    <div className="flex-1">
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-2">
                          {todo.starred && <Star className="w-4 h-4 text-yellow-500 fill-current" />}
                          <span className={`text-white ${todo.completed ? 'line-through opacity-60' : ''}`}>
                            {todo.description}
                          </span>
                        </div>

                        <div className="flex items-center gap-3">
                          <span className="text-neutral-400 text-sm">{todo.time}</span>

                          <div className={`border rounded px-2 py-1 ${priorityColors[todo.priority]}`}>
                            <span className="text-xs">{todo.priority}</span>
                          </div>

                          <ChevronDown className="w-4 h-4 text-neutral-400" />

                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              deleteTodo(todo.id);
                            }}
                            className="text-neutral-500 hover:text-red-500 transition-colors"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </div>

                      {/* Steps indicator */}
                      {todo.steps.length > 0 && (
                        <div className="mt-2 text-sm text-neutral-400">
                          <span>Tasks</span>
                          <span className="mx-2">•</span>
                          <span>{todo.steps.filter(step => step.completed).length} of {todo.steps.length}</span>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {/* Fixed bottom input for new todo */}
            <div className="fixed bottom-0 left-0 right-0 bg-neutral-800 border-t border-neutral-700 p-4" style={{ marginLeft: '364px' }}>
              <div className="flex gap-3">
                <input
                  type="text"
                  placeholder="Add a new to-do..."
                  value={newTodoText}
                  onChange={(e) => setNewTodoText(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && addNewTodo()}
                  className="flex-1 bg-neutral-700 border border-neutral-600 rounded-lg px-4 py-2 text-white placeholder-neutral-400 focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent"
                />
                <button
                  onClick={addNewTodo}
                  className="px-4 py-2 bg-white text-black rounded-lg hover:bg-gray-100 transition-colors"
                >
                  Add
                </button>
              </div>
            </div>
          </div>

          {/* Right Column */}
          <div className="w-80 bg-neutral-700 rounded-lg flex flex-col">
            {!selectedTodo ? (
              // Groups view
              <div className="p-6 flex-1">
                <h3 className="text-white text-lg font-semibold mb-4">My Groups</h3>
                <div className="space-y-3">
                  {groups.map(group => (
                    <div key={group.id} className="flex items-center gap-3 p-3 bg-neutral-600 rounded-lg hover:bg-neutral-500 transition-colors cursor-pointer">
                      <div className={`w-3 h-3 rounded-full ${group.color}`}></div>
                      <span className="text-white">{group.name}</span>
                    </div>
                  ))}

                  <button className="w-full flex items-center gap-3 p-3 border-2 border-dashed border-neutral-500 rounded-lg hover:border-neutral-400 transition-colors">
                    <Plus className="w-4 h-4 text-neutral-400" />
                    <span className="text-neutral-400">Create new group</span>
                  </button>
                </div>
              </div>
            ) : (
              // Todo details view
              <>
                <div className="p-6 flex-1">
                  {/* Header */}
                  <div className="flex items-center gap-3 mb-6">
                    <button
                      onClick={() => setSelectedTodo(null)}
                      className="text-neutral-400 hover:text-white transition-colors"
                    >
                      <ChevronLeft className="w-5 h-5" />
                    </button>
                    <h3 className="text-white text-lg font-semibold">Todo Details</h3>
                  </div>

                  {/* Todo main info */}
                  <div className="flex items-center gap-3 mb-4">
                    <button
                      onClick={() => toggleTodoComplete(selectedTodo.id)}
                      className={`w-6 h-6 rounded border-2 flex items-center justify-center transition-colors ${
                        selectedTodo.completed 
                          ? 'bg-green-500 border-green-500' 
                          : 'border-neutral-400 hover:border-white'
                      }`}
                    >
                      {selectedTodo.completed && <Check className="w-4 h-4 text-white" />}
                    </button>

                    <span className={`text-white flex-1 ${selectedTodo.completed ? 'line-through opacity-60' : ''}`}>
                      {selectedTodo.description}
                    </span>

                    <button
                      onClick={() => toggleStarred(selectedTodo.id)}
                      className={`transition-colors ${
                        selectedTodo.starred 
                          ? 'text-yellow-500' 
                          : 'text-neutral-400 hover:text-yellow-500'
                      }`}
                    >
                      <Star className={`w-5 h-5 ${selectedTodo.starred ? 'fill-current' : ''}`} />
                    </button>
                  </div>

                  {/* Add step button */}
                  <button
                    onClick={() => setShowNewStep(true)}
                    className="w-full flex items-center gap-2 p-3 border border-neutral-600 rounded-lg text-neutral-400 hover:text-white hover:border-neutral-500 transition-colors mb-4"
                  >
                    <Plus className="w-4 h-4" />
                    <span>Add a step</span>
                  </button>

                  {/* Steps */}
                  <div className="space-y-2 mb-6">
                    {selectedTodo.steps.map(step => (
                      <div key={step.id} className="flex items-center gap-3 p-2">
                        <button
                          onClick={() => toggleStepComplete(step.id)}
                          className={`w-4 h-4 rounded border-2 flex items-center justify-center transition-colors ${
                            step.completed 
                              ? 'bg-green-500 border-green-500' 
                              : 'border-neutral-400 hover:border-white'
                          }`}
                        >
                          {step.completed && <Check className="w-2.5 h-2.5 text-white" />}
                        </button>

                        <span className={`text-white flex-1 ${step.completed ? 'line-through opacity-60' : ''}`}>
                          {step.description}
                        </span>

                        <button
                          onClick={() => deleteStep(step.id)}
                          className="text-neutral-500 hover:text-red-500 transition-colors"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    ))}

                    {showNewStep && (
                      <div className="flex items-center gap-3 p-2">
                        <div className="w-4 h-4 rounded border-2 border-neutral-400"></div>
                        <input
                          type="text"
                          placeholder="Step description..."
                          value={newStepText}
                          onChange={(e) => setNewStepText(e.target.value)}
                          onKeyPress={(e) => {
                            if (e.key === 'Enter') {
                              addStep();
                              setShowNewStep(true); // Keep showing for next step
                            }
                          }}
                          onBlur={() => {
                            if (newStepText.trim()) {
                              addStep();
                            }
                            setShowNewStep(false);
                          }}
                          autoFocus
                          className="flex-1 bg-transparent text-white placeholder-neutral-400 focus:outline-none"
                        />
                      </div>
                    )}
                  </div>

                  {/* Action buttons */}
                  <div className="space-y-3 mb-6">
                    <button className="w-full p-3 bg-neutral-600 rounded-lg text-white hover:bg-neutral-500 transition-colors">
                      Remind me
                    </button>
                    <button className="w-full p-3 bg-neutral-600 rounded-lg text-white hover:bg-neutral-500 transition-colors">
                      Set time
                    </button>
                    <button className="w-full p-3 bg-neutral-600 rounded-lg text-white hover:bg-neutral-500 transition-colors">
                      Repeat
                    </button>
                  </div>

                  {/* Notes */}
                  <div>
                    <label className="block text-white text-sm font-medium mb-2">Notes</label>
                    <textarea
                      value={notes}
                      onChange={(e) => setNotes(e.target.value)}
                      placeholder="Add notes..."
                      className="w-full bg-neutral-600 border border-neutral-500 rounded-lg p-3 text-white placeholder-neutral-400 focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent resize-none"
                      rows="4"
                      style={{ minHeight: '100px' }}
                    />
                  </div>
                </div>

                {/* Footer */}
                <div className="border-t border-neutral-700 p-4 flex items-center justify-between">
                  <span className="text-neutral-400 text-sm">Created {selectedTodo.createdAt}</span>
                  <button
                    onClick={() => deleteTodo(selectedTodo.id)}
                    className="text-neutral-500 hover:text-red-500 transition-colors"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default TodosPage;
